using Microsoft.AspNetCore.Http;
using System;
using System.Net.Http;
using System.Threading.Tasks;

public class ProxyMiddleware
{
    private readonly RequestDelegate _next;
    private readonly HttpClient _httpClient;

    public ProxyMiddleware(RequestDelegate next, IHttpClientFactory httpClientFactory)
    {
        _next = next;
        _httpClient = httpClientFactory.CreateClient();
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var originalUrl = context.Request.Path;
        var proxyUrl = context.Request.Scheme + "://" + context.Request.Host + context.Request.Path;

        context.Items["OriginalUrl"] = originalUrl;

        context.Request.Path = proxyUrl;

        var response = await _httpClient.SendAsync(context.Request);

        context.Response.StatusCode = (int)response.StatusCode;

        await response.Content.CopyToAsync(context.Response.Body);
    }
}
